% ylim([0 W_hall]);
xlabel('$x$ [m]','Interpreter','latex'); %[output:7e6b773d]
ylabel('$y$ [m]','Interpreter','latex'); %[output:7e6b773d]
title('Random Waypoint Mobility with Random Pause'); %[output:7e6b773d]
